/**
 * Generates a PDF Blob from text content using jsPDF.
 */
export const generatePdfBlob = async (content: string, title: string = "Transcribed Notes"): Promise<Blob> => {
  const globalJsPDF = (window as any).jspdf;
  if (!globalJsPDF) {
    throw new Error("jsPDF library not loaded");
  }

  const { jsPDF } = globalJsPDF;
  // Default is A4
  const doc = new jsPDF();

  const margin = 20; // mm
  const pageWidth = doc.internal.pageSize.getWidth();
  const pageHeight = doc.internal.pageSize.getHeight();
  const maxLineWidth = pageWidth - (margin * 2);

  let y = 20;

  // Title
  doc.setFont("helvetica", "bold");
  doc.setFontSize(22);
  doc.text(title, margin, y);
  y += 15;

  // Metadata
  doc.setFont("helvetica", "italic");
  doc.setFontSize(10);
  doc.setTextColor(100);
  doc.text(`Generated on: ${new Date().toLocaleDateString()} ${new Date().toLocaleTimeString()}`, margin, y);
  doc.setTextColor(0);
  y += 15;

  const lines = content.split('\n');

  // Helper to check page break
  const checkPageBreak = (heightAdded: number) => {
    if (y + heightAdded > pageHeight - margin) {
      doc.addPage();
      y = margin;
      return true;
    }
    return false;
  };

  lines.forEach(line => {
    let text = line.trim();
    if (!text) {
      y += 5;
      checkPageBreak(0);
      return;
    }

    if (text.startsWith('# ')) {
      doc.setFont("helvetica", "bold");
      doc.setFontSize(16);
      text = text.replace(/^#\s+/, '');
      const splitText = doc.splitTextToSize(text, maxLineWidth);
      const height = splitText.length * 8; // approx line height for 16pt
      checkPageBreak(height);
      doc.text(splitText, margin, y);
      y += height + 4;
    } else if (text.startsWith('## ')) {
      doc.setFont("helvetica", "bold");
      doc.setFontSize(14);
      text = text.replace(/^##\s+/, '');
      const splitText = doc.splitTextToSize(text, maxLineWidth);
      const height = splitText.length * 7;
      checkPageBreak(height);
      doc.text(splitText, margin, y);
      y += height + 3;
    } else if (text.startsWith('- ')) {
      doc.setFont("helvetica", "normal");
      doc.setFontSize(12);
      text = text.replace(/^-\s+/, '');
      const splitText = doc.splitTextToSize(text, maxLineWidth - 8);
      const height = splitText.length * 6;
      checkPageBreak(height);
      doc.text("•", margin, y);
      doc.text(splitText, margin + 6, y);
      y += height + 2;
    } else {
      doc.setFont("helvetica", "normal");
      doc.setFontSize(12);
      const splitText = doc.splitTextToSize(text, maxLineWidth);
      const height = splitText.length * 6;
      checkPageBreak(height);
      doc.text(splitText, margin, y);
      y += height + 2;
    }
  });

  return doc.output('blob');
};

/**
 * Generates and downloads a PDF file.
 */
export const generatePdf = async (content: string, filename: string) => {
  try {
    const blob = await generatePdfBlob(content, filename);
    const saveAs = (window as any).saveAs;
    if (saveAs) {
      saveAs(blob, `${filename}.pdf`);
    } else {
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `${filename}.pdf`;
      document.body.appendChild(a);
      a.click();
      setTimeout(() => {
        document.body.removeChild(a);
        URL.revokeObjectURL(url);
      }, 100);
    }
  } catch (error) {
    console.error("Error generating PDF:", error);
    alert("Could not generate PDF. Please try again.");
  }
};

import React, { useState, useEffect, useCallback } from 'react';
import { 
  Camera, 
  Upload, 
  FileText, 
  Download, 
  Share2, 
  Moon, 
  Sun, 
  Play, 
  Settings,
  Loader2,
  Plus,
  Archive,
  AlertTriangle,
  RefreshCw,
  X
} from 'lucide-react';
import { BatchImage, OCRConfig } from './types.ts';
import CameraCapture from './components/CameraCapture.tsx';
import Editor from './components/Editor.tsx';
import BatchList from './components/BatchList.tsx';
import { processImageOCR } from './services/ocrService.ts';
import { generatePdf, generatePdfBlob } from './services/pdfService.ts';

const App: React.FC = () => {
  const [images, setImages] = useState<BatchImage[]>([]);
  const [currentIndex, setCurrentIndex] = useState<number>(-1);
  const [darkMode, setDarkMode] = useState<boolean>(() => {
    return window.matchMedia('(prefers-color-scheme: dark)').matches;
  });
  const [config, setConfig] = useState<OCRConfig>({
    language: 'eng',
    grayscale: true,
    contrast: 1.2,
    threshold: 128
  });
  const [isCameraOpen, setIsCameraOpen] = useState(false);
  const [isProcessing, setIsProcessing] = useState(false);
  const [isZipping, setIsZipping] = useState(false);
  const [finalText, setFinalText] = useState('');

  const [libsLoaded, setLibsLoaded] = useState(false);
  const [libsError, setLibsError] = useState(false);

  useEffect(() => {
    if (darkMode) {
      document.documentElement.classList.add('dark');
    } else {
      document.documentElement.classList.remove('dark');
    }
  }, [darkMode]);

  const checkLibs = useCallback(() => {
    setLibsError(false);
    let attempts = 0;
    const maxAttempts = 30;

    const check = () => {
      // We check for jspdf in addition to existing libs
      const jspdfReady = (window as any).jspdf;
      const jszipReady = (window as any).JSZip;
      const saveAsReady = (window as any).saveAs;

      if (jspdfReady && jszipReady && saveAsReady) {
        setLibsLoaded(true);
        setLibsError(false);
      } else {
        attempts++;
        if (attempts >= maxAttempts) {
          setLibsError(true);
        } else {
          setTimeout(check, 1000);
        }
      }
    };
    check();
  }, []);

  useEffect(() => {
    checkLibs();
  }, [checkLibs]);

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files) return;

    const newImages: BatchImage[] = Array.from(files).map((file: File) => ({
      id: Math.random().toString(36).substr(2, 9),
      file,
      previewUrl: URL.createObjectURL(file),
      status: 'pending',
      progress: 0
    }));

    setImages(prev => [...prev, ...newImages]);
    if (currentIndex === -1) setCurrentIndex(images.length);
  };

  const handleCapture = (blob: Blob) => {
    const newImage: BatchImage = {
      id: Math.random().toString(36).substr(2, 9),
      file: blob,
      previewUrl: URL.createObjectURL(blob),
      status: 'pending',
      progress: 0
    };
    setImages(prev => [...prev, newImage]);
    setIsCameraOpen(false);
    if (currentIndex === -1) setCurrentIndex(images.length);
  };

  const startBatchProcess = async () => {
    if (isProcessing) return;
    setIsProcessing(true);

    const pendingItems = images
      .map((img, index) => ({ img, index }))
      .filter(item => item.img.status !== 'completed');

    if (pendingItems.length === 0) {
      setIsProcessing(false);
      return;
    }

    let nextIndexToAppend = pendingItems[0].index;
    const completedTexts = new Map<number, string>();
    const CONCURRENCY_LIMIT = 2;
    let queuePointer = 0;

    const tryAppendText = () => {
      setFinalText(prev => {
        let newText = prev;
        while (completedTexts.has(nextIndexToAppend)) {
          const textChunk = completedTexts.get(nextIndexToAppend);
          if (textChunk) {
            newText = newText ? newText + '\n\n' + textChunk : textChunk;
          }
          completedTexts.delete(nextIndexToAppend);
          nextIndexToAppend++;
        }
        return newText;
      });
    };

    const processItem = async (item: { img: BatchImage, index: number }) => {
      setImages(prev => prev.map((img, i) => i === item.index ? { ...img, status: 'processing' } : img));
      try {
        const text = await processImageOCR(
          item.img.previewUrl,
          config,
          (progress) => {
            setImages(prev => prev.map((img, i) => i === item.index ? { ...img, progress } : img));
          }
        );
        setImages(prev => prev.map((img, i) => i === item.index ? { ...img, status: 'completed', processedText: text } : img));
        completedTexts.set(item.index, text);
      } catch (err) {
        console.error(`Error processing image ${item.index}`, err);
        setImages(prev => prev.map((img, i) => i === item.index ? { ...img, status: 'error' } : img));
        completedTexts.set(item.index, "[Error: Transcription failed]");
      } finally {
        tryAppendText();
      }
    };

    const runWorker = async () => {
      while (queuePointer < pendingItems.length) {
        const itemIdx = queuePointer++;
        const item = pendingItems[itemIdx];
        await processItem(item);
      }
    };

    const workers = Array(Math.min(CONCURRENCY_LIMIT, pendingItems.length))
      .fill(null)
      .map(() => runWorker());

    await Promise.all(workers);
    setIsProcessing(false);
  };

  const handleExport = async () => {
    if (!finalText) return;
    try {
      await generatePdf(finalText, "Handwritten_Notes_Export");
    } catch (err) {
      console.error("Export failed:", err);
    }
  };

  const handleDownloadZip = async () => {
    if (!libsLoaded) return;
    const JSZip = (window as any).JSZip;
    const saveAs = (window as any).saveAs;
    const completedImages = images.filter(img => img.status === 'completed');
    if (completedImages.length === 0) return;

    setIsZipping(true);
    try {
      const zip = new JSZip();
      for (let i = 0; i < completedImages.length; i++) {
        const img = completedImages[i];
        const text = img.processedText || "";
        const filename = `Note_Page_${i + 1}`;
        zip.file(`${filename}.txt`, text);
        const pdfBlob = await generatePdfBlob(text, `Note Page ${i + 1}`);
        zip.file(`${filename}.pdf`, pdfBlob);
      }
      const zipBlob = await zip.generateAsync({ type: "blob" });
      saveAs(zipBlob, "Notes_Batch_Export.zip");
    } catch (err) {
      console.error("ZIP Generation failed:", err);
    } finally {
      setIsZipping(false);
    }
  };

  const handleShare = async () => {
    if (!finalText) return;
    const shareData = { title: 'Handwritten Notes Export', text: finalText };
    if (navigator.share) {
      try { await navigator.share(shareData); } catch (err) { console.log('Share failed', err); }
    } else {
      navigator.clipboard.writeText(finalText);
      alert('Text copied to clipboard!');
    }
  };

  const processedCount = images.filter(img => img.status === 'completed').length;
  const isAllDone = images.length > 0 && processedCount === images.length;

  return (
    <div className="max-w-6xl mx-auto px-4 py-8">
      <header className="flex justify-between items-center mb-10">
        <div className="flex items-center gap-3">
          <div className="p-3 bg-primary-600 rounded-2xl shadow-lg">
            <FileText className="text-white w-8 h-8" />
          </div>
          <div>
            <h1 className="text-3xl font-extrabold tracking-tight">ScribbleToDoc</h1>
            <p className="text-slate-500 text-sm font-medium">OCR for Handwritten Notes</p>
          </div>
        </div>
        <button 
          onClick={() => setDarkMode(!darkMode)}
          className="p-3 rounded-full hover:bg-slate-200 dark:hover:bg-slate-800 transition-colors"
        >
          {darkMode ? <Sun className="w-6 h-6" /> : <Moon className="w-6 h-6" />}
        </button>
      </header>

      {!libsLoaded && !libsError && (
        <div className="mb-6 p-4 bg-amber-50 dark:bg-amber-900/20 border border-amber-200 dark:border-amber-800 rounded-2xl flex items-center gap-3 text-amber-700 dark:text-amber-400">
          <Loader2 className="w-5 h-5 animate-spin" />
          <p className="text-sm font-medium">Loading PDF generation libraries...</p>
        </div>
      )}

      {libsError && (
        <div className="mb-6 p-4 bg-red-50 dark:bg-red-900/20 border border-red-200 dark:border-red-800 rounded-2xl flex items-center justify-between text-red-700 dark:text-red-400">
          <div className="flex items-center gap-3">
            <AlertTriangle className="w-5 h-5" />
            <p className="text-sm font-medium">Library load error. Export disabled.</p>
          </div>
          <button onClick={checkLibs} className="px-3 py-1.5 bg-red-100 dark:bg-red-900/40 rounded-lg text-xs font-bold flex items-center gap-1">
            <RefreshCw className="w-3 h-3" /> Retry
          </button>
        </div>
      )}

      <main className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        <div className="lg:col-span-5 space-y-6">
          <section className="bg-white dark:bg-slate-900 rounded-3xl p-6 shadow-sm border border-slate-100 dark:border-slate-800">
            <div className="flex items-center justify-between mb-6">
              <h2 className="text-lg font-bold flex items-center gap-2">
                <Camera className="w-5 h-5 text-primary-500" />
                Input Source
              </h2>
            </div>
            <div className="grid grid-cols-2 gap-4">
              <button onClick={() => setIsCameraOpen(true)} className="flex flex-col items-center justify-center p-6 border-2 border-dashed border-slate-200 dark:border-slate-800 rounded-2xl hover:border-primary-400 hover:bg-primary-50 dark:hover:bg-primary-900/10 transition-all group">
                <Camera className="w-8 h-8 mb-2 text-slate-400 group-hover:text-primary-500" />
                <span className="text-sm font-semibold">Camera Scan</span>
              </button>
              <label className="flex flex-col items-center justify-center p-6 border-2 border-dashed border-slate-200 dark:border-slate-800 rounded-2xl hover:border-primary-400 hover:bg-primary-50 dark:hover:bg-primary-900/10 transition-all group cursor-pointer">
                <Upload className="w-8 h-8 mb-2 text-slate-400 group-hover:text-primary-500" />
                <span className="text-sm font-semibold text-center">Upload File</span>
                <input type="file" multiple accept="image/*" className="hidden" onChange={handleFileUpload} />
              </label>
            </div>
          </section>

          <section className="bg-white dark:bg-slate-900 rounded-3xl p-6 shadow-sm border border-slate-100 dark:border-slate-800">
            <div className="flex items-center justify-between mb-6">
              <h2 className="text-lg font-bold flex items-center gap-2">
                <Settings className="w-5 h-5 text-primary-500" />
                OCR Settings
              </h2>
            </div>
            <div className="space-y-4">
              <div>
                <label className="text-xs font-bold text-slate-400 uppercase mb-2 block tracking-wider">Language</label>
                <select 
                  className="w-full p-2 bg-slate-50 dark:bg-slate-800 rounded-lg outline-none focus:ring-2 focus:ring-primary-500"
                  value={config.language}
                  onChange={(e) => setConfig({...config, language: e.target.value})}
                >
                  <option value="eng">English</option>
                  <option value="spa">Spanish</option>
                  <option value="fra">French</option>
                  <option value="deu">German</option>
                </select>
              </div>
              <div className="flex items-center justify-between">
                <span className="text-sm font-medium">Auto-Enhance Image</span>
                <input type="checkbox" checked={config.grayscale} onChange={(e) => setConfig({...config, grayscale: e.target.checked})} className="w-4 h-4 rounded text-primary-600 focus:ring-primary-500" />
              </div>
            </div>
          </section>

          <section className="bg-white dark:bg-slate-900 rounded-3xl p-6 shadow-sm border border-slate-100 dark:border-slate-800">
            <div className="flex items-center justify-between mb-4">
              <h2 className="text-lg font-bold">Queue ({images.length})</h2>
              {images.length > 0 && (
                <button onClick={() => {setImages([]); setFinalText(''); setCurrentIndex(-1);}} className="text-red-500 text-xs font-bold hover:underline">Clear</button>
              )}
            </div>
            <BatchList items={images} onRemove={(id) => { const newItems = images.filter(img => img.id !== id); setImages(newItems); if (newItems.length === 0) setCurrentIndex(-1); }} onSelect={(index) => setCurrentIndex(index)} activeIndex={currentIndex} />
            {images.length > 0 && (
              <div className="mt-6 space-y-3">
                <button onClick={startBatchProcess} disabled={isProcessing || isAllDone} className="w-full py-4 bg-primary-600 hover:bg-primary-700 disabled:bg-slate-300 text-white rounded-2xl font-bold flex items-center justify-center gap-2 transition-transform active:scale-95 shadow-lg shadow-primary-200">
                  {isProcessing ? <Loader2 className="w-5 h-5 animate-spin" /> : <Play className="w-5 h-5" />}
                  {isProcessing ? `Processing...` : isAllDone ? "Done" : "Start Conversion"}
                </button>
                {processedCount > 0 && (
                  <button onClick={handleDownloadZip} disabled={isZipping || isProcessing || !libsLoaded} className="w-full py-3 border-2 border-primary-500 text-primary-600 dark:text-primary-400 rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-primary-50 transition-colors disabled:opacity-50">
                    {isZipping ? <Loader2 className="w-5 h-5 animate-spin" /> : <Archive className="w-5 h-5" />}
                    Download ZIP (PDFs)
                  </button>
                )}
              </div>
            )}
          </section>
        </div>

        <div className="lg:col-span-7 space-y-6">
          <section className="bg-white dark:bg-slate-900 rounded-3xl shadow-sm border border-slate-100 dark:border-slate-800 min-h-[500px] flex flex-col overflow-hidden">
            <div className="p-4 border-b border-slate-100 dark:border-slate-800 flex items-center justify-between bg-slate-50/50 dark:bg-slate-800/30">
              <h2 className="text-lg font-bold">Document</h2>
              <div className="flex gap-2">
                <button onClick={handleShare} disabled={!finalText} className="p-2.5 rounded-xl border border-slate-200 dark:border-slate-700 hover:bg-white transition-colors disabled:opacity-30">
                  <Share2 className="w-5 h-5" />
                </button>
                <button onClick={handleExport} disabled={!finalText || !libsLoaded} className="px-5 py-2.5 bg-red-600 hover:bg-red-700 text-white rounded-xl font-bold text-sm flex items-center gap-2 transition-colors disabled:opacity-30 disabled:bg-slate-400">
                  <Download className="w-4 h-4" /> PDF
                </button>
              </div>
            </div>
            <div className="flex-1 p-6">
               <Editor content={finalText} onChange={(val) => setFinalText(val)} placeholder="Transcribed notes will appear here..." />
            </div>
          </section>
        </div>
      </main>

      {isCameraOpen && (
        <div className="fixed inset-0 z-50 bg-black/80 backdrop-blur-sm flex items-center justify-center p-4">
          <div className="bg-white dark:bg-slate-900 rounded-3xl w-full max-w-2xl overflow-hidden relative">
            <button onClick={() => setIsCameraOpen(false)} className="absolute top-4 right-4 z-10 p-2 bg-black/20 rounded-full text-white hover:bg-black/40">
              <X className="w-6 h-6" />
            </button>
            <CameraCapture onCapture={handleCapture} />
          </div>
        </div>
      )}

      {images.length === 0 && !isCameraOpen && (
        <div className="fixed bottom-8 left-1/2 -translate-x-1/2 max-w-md w-full px-6 py-4 bg-white/80 dark:bg-slate-900/80 backdrop-blur border border-slate-200 dark:border-slate-800 rounded-2xl shadow-xl flex items-center gap-4 animate-bounce z-40">
          <div className="p-2 bg-primary-100 rounded-lg">
            <Plus className="w-5 h-5 text-primary-600" />
          </div>
          <p className="text-sm font-medium text-slate-600 dark:text-slate-400">Scan or upload handwritten notes to start!</p>
        </div>
      )}
    </div>
  );
};

export default App;

